import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider } from './contexts/AuthContext';
import FigmaHome from './pages/FigmaHome';
import FigmaLogin from './pages/FigmaLogin';
import FigmaRegister from './pages/FigmaRegister';
import './styles/figma.css';

function App() {
    return (
        <Router>
            <AuthProvider>
                <Routes>
                    <Route path="/" element={<FigmaHome />} />
                    <Route path="/login" element={<FigmaLogin />} />
                    <Route path="/register" element={<FigmaRegister />} />
                </Routes>
                <Toaster position="top-right" />
            </AuthProvider>
        </Router>
    );
}

export default App;
